policies.inbound:










            client_id must match the configured Claude public client.





            response_type must be code.





            redirect_uri is not allowlisted for the configured Claude public client.





            PKCE S256 is required.



<set-variable name="authorizeQueryString" value="@{
    var query = context.Request.Url.Query;
    var scopeValues = query.ContainsKey("scope") ? query["scope"] : new string[0];
    // MCP clients may send scope with + as space (form-urlencoded style); normalize to real space before splitting.
    var scope = scopeValues.Length > 0 ? Uri.UnescapeDataString(scopeValues[0].Replace("+", "%20")) : "";
    if (string.IsNullOrWhiteSpace(scope))
    {
        scope = "{{McpScope}} offline_access";
    }
    else
    {
        var requestedScopes = scope
            .Split(new[] { ' ' }, StringSplitOptions.RemoveEmptyEntries)
            .ToList();

        if (!requestedScopes.Any(token => string.Equals(token, "{{McpScope}}", StringComparison.OrdinalIgnoreCase)))
        {
            requestedScopes.Add("{{McpScope}}");
        }

        if (!requestedScopes.Any(token => string.Equals(token, "offline_access", StringComparison.OrdinalIgnoreCase)))
        {
            requestedScopes.Add("offline_access");
        }

        scope = string.Join(" ", requestedScopes);
    }

    var pairs = new System.Collections.Generic.List();
    foreach (var item in query)
    {
        // Drop scope (re-added below with the normalized value) and resource.
        // Entra v2 doesn't honor RFC 8707 resource indicators; leaving resource= in
        // the forwarded URL triggers AADSTS9010010 when it doesn't match the scope's
        // app identifier URI. APIM validates audience downstream at /mcp instead.
        if (string.Equals(item.Key, "scope", StringComparison.OrdinalIgnoreCase) ||
            string.Equals(item.Key, "resource", StringComparison.OrdinalIgnoreCase))
        {
            continue;
        }

        foreach (var value in item.Value)
        {
            pairs.Add(Uri.EscapeDataString(item.Key) + "=" + Uri.EscapeDataString(Uri.UnescapeDataString(value)));
        }
    }

    pairs.Add(Uri.EscapeDataString("scope") + "=" + Uri.EscapeDataString(scope));

    return string.Join("&", pairs);
}" />



        @("https://login.microsoftonline.com/{{McpTenantId}}/oauth2/v2.0/authorize?" + (string)context.Variables["authorizeQueryString"])
